mapper.select:
SELECT CASE WHEN COUNT(*) > 0 THEN TRUE ELSE FALSE END
FROM donations
WHERE kofi_message_id = #{kofiMessageId}

mapper.update:
UPDATE donations
SET wikisprint_account_id = NULL
WHERE wikisprint_account_id = #{accountId}

UPDATE donations
SET supporter_name = #{supporterName}
WHERE donation_id = #{donationId}
  AND type != 'PendingTransfer'

UPDATE donations
SET message = #{message}
WHERE donation_id = #{donationId}
  AND type != 'PendingTransfer'

mapper.delete:
DELETE FROM donations
WHERE donation_id = #{donationId}
  AND type != 'PendingTransfer'
